package main import ( "flag" "fmt" "log" "github.com/go-ldap/ldap"
) func main() { uid := flag.String("uid", "", "User-Id e.g. jw163") password := flag.String("pw", "", "Password e.g. password") flag.Parse() ldapURL := "ldaps://ldap1.mi.hdm-stuttgart.de" l, err := ldap.DialURL(ldapURL) if err != nil { log.Fatal(err) } defer l.Close() err = l.Bind(fmt.Sprintf("uid=%s, ou=userlist,dc=hdm-stuttgart,dc=de", *uid), *password) if err != nil { log.Fatal(err) } BaseDN := "dc=hdm-stuttgart,dc=de" Filter := fmt.Sprintf("(uid=%s)", *uid) searchReq := ldap.NewSearchRequest( BaseDN, ldap.ScopeWholeSubtree, ldap.NeverDerefAliases, 0, 0, false, Filter, []string{}, nil, ) result, err := l.Search(searchReq) if err != nil { log.Fatal(err) } if len(result.Entries) > 0 { result.PrettyPrint(4) } else { fmt.Println("Couldn't fetch search entries") }
} When executing the program, the output looks like this: $ go run main.go --uid=jw163 --pw=CENSORED DN: uid=jw163,ou=userlist,dc=hdm-stuttgart,dc=de objectClass: [hdmAccount hdmStudent inetOrgPerson posixAccount shadowAccount eduPerson] uid: [jw163] mail: [jw163@hdm-Stuttgart.de] uidNumber: [67828] cn: [Waibel Jakob Elias] loginShell: [/bin/sh] hdmCategory: [1] gidNumber: [100] givenName: [Jakob Elias] homeDirectory: [/home/stud/j/jw163] sn: [Waibel] matrikelNr: [40062]
